const presetName = "fire";
export async function loadFirePreset(engine) {
    await engine.pluginManager.register(async (e) => {
        const [{ loadBasic }, { loadInteractivityPlugin }, { loadExternalPushInteraction }, { options }] = await Promise.all([
            import("@tsparticles/basic/lazy"),
            import("@tsparticles/plugin-interactivity/lazy"),
            import("@tsparticles/interaction-external-push/lazy"),
            import("./options.js"),
        ]);
        await Promise.all([
            loadBasic(e),
            (async () => {
                await loadInteractivityPlugin(e);
                await loadExternalPushInteraction(e);
            })(),
        ]);
        e.pluginManager.addPreset(presetName, options);
    });
}
